import test from 'node:test';
import assert from 'node:assert/strict';

import { OffsetTracker } from '../src/offset-tracker.mjs';
import { processBatch } from '../src/batch-consumer.mjs';
import { formatCommitReport } from '../src/commit-report.mjs';

function deferred() {
  let resolve;
  const promise = new Promise((settle) => {
    resolve = settle;
  });
  return { promise, resolve };
}

function afterTurn() {
  return new Promise((resolve) => setImmediate(resolve));
}

test('a mixed batch always leaves a restart-safe operator report', async () => {
  const tracker = new OffsetTracker({
    'orders:1': 100,
    'orders:2': 200
  });
  const gates = new Map([
    ['first', deferred()],
    ['second', deferred()],
    ['other', deferred()]
  ]);

  const processing = processBatch(
    [
      { id: 'first', topic: 'orders', partition: 1, offset: 101 },
      { id: 'second', topic: 'orders', partition: 1, offset: 102 },
      { id: 'other', topic: 'orders', partition: 2, offset: 201 }
    ],
    async (record) => {
      await gates.get(record.id).promise;
      return `${record.id}:done`;
    },
    tracker
  );

  gates.get('second').resolve();
  gates.get('other').resolve();
  await afterTurn();

  assert.equal(tracker.committed('orders', 1), 100);
  assert.equal(tracker.committed('orders', 2), 201);

  gates.get('first').resolve();
  const outcomes = await processing;

  assert.deepEqual(
    outcomes.map((outcome) => outcome.result),
    ['first:done', 'second:done', 'other:done']
  );
  assert.equal(
    formatCommitReport(tracker.snapshot()),
    'orders:1@102, orders:2@201'
  );
});
